dsl:
@schema 1
@namespace "t"
@name "t"
@version "1.0.0"

def ACL mask_email {
  action: "read"
  resource: "email"
  roles: ["user"]
  effect: "allow"
  maskFields: ["email"]
}

def FormDef signup "Signup" {
  def FieldDef email "Email" { type: "string" required: true }
  def FieldDef name "Name" { type: "string" }
}
